queries.sparql:
PREFIX : <http://ambrosia.example.org/hospitality#>
PREFIX p: <http://ambrosia.example.org/hospitality/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?guestrooms a :GuestRooms .
    ?guestrooms p:room ?room .
    BIND(?room AS ?o0)
  }
  UNION
  {
    ?suites a :Suites .
    ?suites p:suite_name ?suite_name .
    ?suites p:amenities ?amenities_f .
    FILTER(STR(?amenities_f) = "Air Conditioning")
    BIND(?suite_name AS ?o0)
  }
}

